import{c as e,Q as i,j as a,m as r}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"关于奥尔西尼家族的事，他","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/11-关于奥尔西尼家族的事，他.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/11-关于奥尔西尼家族的事，他.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/upper/11-关于奥尔西尼家族的事，他.md"};function c(t,p,l,s,_,m){return i(),a("div",null,[...p[0]||(p[0]=[r('<h1 id="关于奥尔西尼家族的事-他" tabindex="-1">关于奥尔西尼家族的事，他 <a class="header-anchor" href="#关于奥尔西尼家族的事-他" aria-label="Permalink to &quot;关于奥尔西尼家族的事，他&quot;">​</a></h1><p>关于奥尔西尼家族的事，他沉思了片刻，接着说： &quot;你们必须维持与 国王陛下的友谊，这样，你们根本用不着他帮助；而一旦你们失去他的恩 典，任何帮助都将无济于事。”我回答得恰到好处，我觉得最好不要涉及 或回答关于卢卡人的事情，因为直到诸位大人的大使到来之前，我不愿意 再刺激他们的盟友，而只想维持现状；希望大使带来的指示能够使国王陛 下满意，这样一来，我们就可以更加自由宽松地讨论类似的问题，尤其是 目前大使已经离开了佛罗伦萨，应该很快就会到达。过了诸灵节①,我收 到了诸位大人上月10日寄出的信件，在仔细研究了信中的内容后，我又回 去找鲁昂教座大人，简短地向他解释了诸位大人担心的原因：瓦伦蒂诺公 爵夺取法恩扎后，就可以轻而易举地将灾祸导向诸位大人，还有佛罗伦萨 城内的一群反叛者做内应，非常容易就能将诸位大人的自由毁于一旦，这 样一来，既会给诸位大人带来灾难，又会使国王陛下的荣誉受损；既然我 们是国王陛下最忠实、亲密的盟友，那么教座大人给教皇陛下和瓦伦蒂诺</p><p>①又称万灵节、追思亡者节，11月2日。——中译者注</p><p>公爵写一封这样的信就是合情合理的，告诉他们无论对诸位大人采取什么 敌对行动都会被视为针对国王陛下。教座大人拉着我的手，把我带到了首 席大臣和洛特林侯爵①面前，他们就在旁边；然后，他从那里开始回答， 他有好多次都说过，他为了诸位大人的利益不辞劳苦，国王陛下出于对 你们的爱遭受了名誉损失；而你们却违背条约，拒付应该支付的钱款； 你们现在害怕教皇了，才想得到国王陛下的恩惠，如果不是为了更好地了 解你们是否真的是他的盟友的话，国王陛下当然可以不予理睬；因为如果 我写任何东西符合你们的利益，将会损害卢卡人、锡耶纳人以及其他你们 敌人的利益，如果国王陛下失去诸位大人这样的朋友的话，他将不会把那 些人看成自己的敌人。我对第一部分的回答如同我重复过许多遍的一样； 至于其他方面，我说我不认为到目前为止诸位大人的友谊还有什么怀疑， 我也不认为国王陛下在帮助诸位大人的时候会考虑卢卡人或锡耶纳人的利 益，因为我不记得他们曾经做过多少符合国王陛下利益的事情，我也不知 道无论在和平还是战争期间他们能够或希望做些什么贡献，但我清楚地知 道诸位大人为这位国王陛下和前任国王所做的一切，在国王处于逆境、盟 友的忠诚接受考验时，诸位大人仍然是意大利诸侯中唯一忠心耿耿的盟 友，但诸位大人却没有得到与之相配的对待，因为诸位大人的功绩没有得 到承认，而且笃信王陛下不应该允许这种事情发生。枢机主教只用下面一 句话回答我：“给你们的大使写信，叫他赶紧来，还有把指示寄给你，以 便我们知道执政团的意思，然后，我们一定不会忘记告知执政团该做的事 情。”我告诉他教皇已于12日派特使去了比萨；他怒气冲冲地答道，这有 什么;我该做好他指示我做的事情，等等。 第二天，也就是昨天，罗贝泰遇见了我，他对我说： “我得到国王陛 下和教座大人给我的一项特殊命令，要我写信给米兰的奥比尼大人和在罗 马的大使，指示二人，一个去面见教皇，另一个去面见瓦伦蒂诺公爵，通</p><p>①菲利普 · 霍赫贝格( Philippe de Hochberg), 纳沙泰尔伯爵，勃艮第的元帅和普罗旺斯的统治者。 贝尔泰利编校本注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>报他们，国王陛下了解到有传言说前者的军队目前正在罗马涅，而后者的 军队正与反叛者或其他敌人勾结准备进攻佛罗伦萨，他是多么不悦，国王 陛下无论如何都不会容忍这样的事情发生。”总而言之，他告诉我他得到 的命令是信要尽可能写得义正词严，以维护诸位大人的利益。当我问他索 要这封信的时候，他说他没有得到命令这么做，并且他认为最好也是如 此，因为否则的话，似乎是我们要求写这封信的。 这就是我要向诸位大人报告的全部情况，以回复你们的上一封信。这 里没有什么新的消息要汇报，除了国王陛下今天离开前往图尔，在那里听 取德意志大使的报告。再会!</p><p>发自南特，1500年11月4日 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件26①</p><p>尊敬的诸位大人： 我是在本月4日写信给我们杰出执政团的，回复他们上月11日和24日 的信。在此之后，国王陛下离开南特前往图尔，我决定同宫廷一起移动 (尽管他们走的是岔道)。我考虑诸位大人回复奥多瓦尔多 · 布留奥托代 表国王陛下向杰出的执政团所提之建议的信会在这个时候寄到，正如我所 料，就在国王陛下抵达香槟(一个距离图尔大约10里格的小村庄)的时 候，诸位大人的信寄到了，连同我们杰出执政团给奥多瓦尔多的答复。 我本月18日大约晚上2点到达的时候，我将传达诸位大人指示的时间推迟 到了上午。第二天上午，我到了宫廷，碰巧遇到鲁昂教座大人，他独自一</p><p>①这封信是写给前面提到的重新成立的“自由与和平十人委员会”的。 ——英译本注</p><p>人，亦很悠闲，我觉得应该抓住这个机会，尽管我的初衷是先和国王陛下 面谈；我走到教座大人身边告诉他，我刚刚收到诸位大人的来信，其中的 一份副本对奥多瓦尔多带去的意见给出了答复，没有必要重复其中的内 容，因为通过奥多瓦尔多本人非常详细的讲述，国王陛下已经知道这个事 情了。我随后补充说，考虑到他所处环境的迫切性，执政团的答复和决定 可能无法让国王陛下完全满意；然而，从另一方面考虑，执政团遇到了并 且仍将面临困境，负担了、正在负担着并且将来仍然要负担沉重的费用， 一直在为维持法国在意大利的赫赫威名而努力，却无法得到属于自己的东 西，执政团相信笃信王陛下一定会接受他们的决定， 一定愿意承担这笔钱 款的部分延迟支付所带来的不便，至少也应该念及我城为国王陛下做出的 种种贡献。如果能够收复彼得拉桑塔，这不仅是理所当然的，而且是执政 团的忠诚应得的回报，既遵守了条约规定，又让卢卡人的阴谋诡计不能得 逞，这将使执政团完全振兴起来，必将极大地鼓舞佛罗伦萨人民，纵使捐 钱舍命，也要为笃信王陛下效力；还会为他们恢复声誉，使教皇和威尼斯 人都不敢像现在这样肆无忌惮地入侵他们的国家和损害他们的自由。只要 教座大人的耐心允许，我就一直滔滔不绝地阐述。教座大人回答说，通过 回复奥多瓦尔多，诸位大人的确承认了他们所欠国王陛下的债务，并且命 令马上支付给米兰10000达克特，但这并不能使国王陛下满意，他在从你 们的账户上报销这笔钱款的过程中忍受了相当的不便；如果这笔钱款无法 全额支付，国王陛下就无法再谈什么维护执政团的利益了；而我自己还有 大使，无论什么时候到，得到的一定是国王陛下的负面答复。因为时间宽 裕，我能从容不迫地详细回答，尽管国王陛下的不悦千真万确，却并非合 情合理：不是从他要拿回属于自己的东西的角度，而是从他应该像父亲对 待儿子那样行事为人的角度，他在接受他们的行为时，不是从他自己的意 愿而是从他们的能力出发；在这一点上，我按照这件事情的性质给我的启 示阐释了那些理由，教座大人没有给出任何其他结论，只是说这笔钱是 国王陛下用来支付他在伦巴第骑兵的军费的；如果诸位大人想要推迟一</p><p>点时间支付这笔钱的一部分，你们必须同米兰的总督奥比尼大人和肖蒙大 人①协商；如果他们同意等上几个月的话，国王陛下也没什么意见。我反 驳说，这样的回答不是我期望的，也不是我们的共和国深信不疑的；因为 我知道这会使执政团屈辱不堪且威信扫地，我不会写这些；因为我坚信， 没有了任何希望的执政团不会再追求任何利益，而是完全自暴自弃；我认 为这既不会给国王也不会给执政团带来益处，我不会写它的；我宁愿期待 其他答复，既对得起执政团的忠心耿耿，也与笃信王王室相称。无法得到 教座大人任何实质性的东西，我只得离开。同一天上午，我面见了国王， 同他谈起同样的话题，我在谈话中尽我所能用那些声情并茂和感染力强的 言辞，向国王表明执政团的忠心，还有诸位大人是多么期望能够满足国王 陛下，以及国王陛下是多么轻而易举就能表现他对执政团的仁爱，我还解 释了那笔钱目前还无法足额支付的原因。为了不使诸位大人厌烦，我不再 重复同一件事，我没有遗漏讲述有关这件事的任何值得关注的细节。然 而，除了老生常谈的抱怨要支付的钱款以及由于我们的过错导致他的军队 声誉扫地之外，我无法得到国王陛下的正面回复；尽管我有礼有节地一一 作答，但还是无法在任何事情上说服他，也无法从谈话中得到任何成果。 同一天，我们到了图尔之后，我同一位朋友进行了面谈，我习惯从他那里 得到相当多关于教皇的秘密情报，尤其是教皇同威尼斯人目前正在进行之 中的密谋，他向我透露，国王陛下的大使去了威尼斯，收受了教皇大使的 贿赂，此人在威尼斯元老院发表演讲，说从多种渠道得知并且确信无疑， 佛罗伦萨人、博洛尼亚人、费拉拉公爵和曼托瓦侯爵正团结一致，以相互 防御为借口形成一个紧密的联盟；而事实上，他们的目的是，只要德意志 皇帝在伦巴第发动攻势，他们就调集军队，对付国王陛下；因此，诸位杰 出的大人必须小心谨慎地对待这个问题，并将此事通报国王陛下，使国王 能承担义务，做与得到的利益相符的事情，等等。对此，威尼斯元老院回</p><p>①查理 · 德 · 安布瓦兹( Charles dAmboise),肖蒙的领主。——贝尔泰利编校本注</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>答说，这件事非常可能发生，因为所有提到的那些势力都武装起来了，并 表现出对法国的不满情绪，元老院要写信给他们的大使，也要写信将此事 报告给国王陛下。除此之外，这位朋友还告诉我，此地的教皇大使也表达 了这样的指示，劝说国王陛下相信此事；更进一步，为了避免陷入这种尴 尬，他可以重新在佛罗伦萨扶植皮耶罗 ·德 ·梅迪奇，并通过类似的方式 在这个城邦建立一个效忠自己的政府；如此一来，他就可以使费拉拉、曼 托瓦和博洛尼亚联盟群龙无首，进而使他们无法叛乱谋反。那个朋友还补 充说，教皇陛下的职责要求这么做，因为只要梅迪奇家族的枢机主教还是 教会里的人，就会请求教皇陛下让他重返家国，而教皇收到他这些合情合 理的请求，也不得不屈尊允许，出手相助。但是，教皇要求法国国王不得 提供援助，只能保持中立，如果后者答应这么做的话，那就无异于向世人 昭示，他已经抛弃同执政团的友谊，并向其他势力而不是你们提供保护， 从而确立教皇的声誉；在短时间内，拥兵自重的教皇就会受到鼓舞，威 尼斯人加入他的行列，对乔瓦尼 ·本蒂沃利奥，会夺取他的国家，对执政 团，将在佛罗伦萨扶植皮耶罗 ·德 ·梅迪奇，对费拉拉人和曼托瓦人则会 在他们的脖子上套上锁链。这个战事会让教皇获得更多声誉，也会刺激他 更大的欲望，他请求法国国王，不仅同意他的行动，而且还派出几百名长 矛兵到博洛尼亚边境，威尼斯人也会调动他们的部队到最需要他们的地方 去。这位朋友还告诉我，所有这些事情都在紧锣密鼓地进行着，因此他们 催促、请求和纠缠国王陛下对此表示赞同；正是由于这个原因，他们将皮 耶罗 ·德 ·梅迪奇从法国请了出来，带到比萨，以便在实施阴谋时用得着 他。听到这些，我觉得我们至圣至高的教皇陛下是干得出这样的事情来 的，于是，我决定就此同鲁昂教座大人谈一谈；抓住一个非常合适的机 会，我向他抱怨执政团的那些敌人居心叵测，但只是泛泛而论，没有特指 教皇或者威尼斯人；说他们自以为能让国王陛下相信，诸位大人想疏远国 王陛下；我也不是为了反对这些突如其来而又无耻卑鄙的灾难而提到我们 过去的忠诚或现在的证据，而仅仅希望表明，说诸位大人期望皇帝的援</p><p>Legazioni,commissarie,scrittidi governo</p><p>助是多么不合情理，他甚至对自认为属于他的米兰都不能提供救援或防 卫；①明白这一点的话，你们会愿意因为他的缘故而甘冒如此大的危险并 承担如此高的代价来与一位你们一直在为之尽忠职守的国王为敌?我也无 法理解，除了法国国王陛下之外，博洛尼亚人或费拉拉人还能把希望寄托 在谁人身上，在任何情况下，他们的国家只能与占领米兰的任何人同舟共 济：前者对教皇心存恐惧，后者对威尼斯人畏之如虎。然而，这位国王陛 下本应防范那些试图消灭他盟友的人，到头来却使那些人的权势渐渐坐 大，并且轻而易举地从他手里夺走意大利的利益。国王陛下应该采取一些 措施阻止那些想在某个外省建立自己权势的人，压制豪强、安抚臣民、维 持盟友、防范同伙(也就是说那些想在行省分享相同权力的人);如果国 王陛下定睛查看是谁希望在意大利成为他的同伙分享权力，他会发现不是 执政团，也不是费拉拉，更不是博洛尼亚，而是那些一直以来都千方百计 试图控制该地区的人。教座大人耐心地听我说完，然后回答说，国王是非 常审慎的人，有着很长的耳朵和很短的信念，也就是说他会倾听各种声 音，但只信任他亲手触摸过的、认定无疑的事情；除了前些时候给罗马和 米兰写过信，当我第一次问起他这件事时，他刚刚在3天前又写了信，完 全出于他自己的动机，热切地嘱托你们的事情。虽然阿莱格里大人②已被 获准率领100名长矛兵进军罗马涅，增援瓦伦蒂诺公爵，但那是为了执政 团利益的明确任务；并且，执政团会看到，当你们的大使到来时，如果你 们信守承诺，在支付这笔钱款等方面提出更优惠条件的话，国王陛下绝不 会不履行自己的责任。在此之后，罗贝泰对我说过同样的话，他向我保 证，只要佛罗伦萨人不要在内部搞得四分五裂，不要在城内庇护那些丝毫 不热爱城邦自由的人——诸位大人应当警惕这种自我伤害，国王陛下本人 就绝不会做什么对你们有害的事情，也不会允许其他人这么做。在回答有</p><p>①“摩尔人”洛多维科 · 斯福尔扎为了取得神圣罗马帝国皇帝马克西米利安一世的支持，成为米兰公 爵，把自己的侄女比安卡嫁给了他，并提供巨额嫁妆，但在法王路易十二对米兰提出权利要求攻占米兰 时，并没有得到帝国的有效支持。 ——中译者注 ②伊夫 · 德 · 图尔泽勒( Yves de Tourzel), 阿莱格里男爵。 ——贝尔泰利编校本注</p><p>关城邦内部分裂的问题上，我轻而易举地维护了执政团的立场，祛除他们 的这种看法乃是当务之急，因为仅仅是这种看法就能在此地产生极恶劣的 影响，以为佛罗伦萨实际就是如此。我没有别的重要事情汇报；因为没有 人说起德意志大使到达此地后带来的提议，那些前去拜访他们的人以及过 分好奇地谈论他们的人都受到关注并被监视。 在我写这封信的时候，我收到了一封来自皮耶罗 · 弗朗切斯科 ·托辛 吉的信，这是对我尝试着给他写的几封信的回复，我从这封信中得知，杰 出的大使阁下已经在本月12日到达里昂，并于15日从那里动身前往此地。 我满怀希望地等待着他，愿上帝赐予他更好的命运，远胜于迄今为止承担 此任务的人。 感谢诸位大人的善意恩惠，再 会 !</p><p>发自图尔，1500年11月21日 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件27①</p><p>尊敬的诸位大人： 在21日的信中，我回复了诸位大人的信，向你们详细报告了国王陛下 和枢机主教有关杰出的执政团对奥多瓦尔多的回复所说的话。我也写了教 皇和威尼斯人密谋行事，使诸位大人受到国王陛下的猜忌怀疑；此外，还 写了鲁昂教座大人就此事对我说的话。尽管没有什么特别的消息好写，但 我还是利用有人要启程前往佛罗伦萨的便利，向诸位大人报告自上一封信 之后这里发生的事情。他们对我关于执政团最近做出的支付所欠国王陛下</p><p>①致自由与和平十人委员会。贝尔泰利编校本此信中有部分标记为加密内容(中译以〈〉标注，下 同),英译本未标出。 ——中译者注</p><p>Legazioni,commissarie,scrittidi governo</p><p>钱款问题的答复并不十分满意；这里得到最新的消息，瓦伦蒂诺公爵已经 占领了拉莫纳谷，并打算继续夺取法恩扎；后来又听说，皮耶罗 ·德 ·梅 迪奇已经到了比萨；此外，还有另外一位卢卡的大使来到此地，据说他带 着指令，要立刻向国王陛下支付10000达克特，条件是把彼得拉桑塔交给 他们；除此之外，拉帕利斯大人①和夏蒂永大人②已经被王后委派到比萨 做总督。考虑到这些，我决定再次面见国王陛下向他表明，如果我们杰出 的执政团对奥多瓦尔多的答复不能令国王陛下满意的话，其原因是已经绝 对不可能做得更好了，因为执政团已经承担并且还要继续承担如此沉重的 负担，而且瓦伦蒂诺公爵那支常胜军已兵临城下，不停地威胁要进攻执 政团，并不是以他自己的军队，而是动用国王陛下的部队；在任何事情 上，他都吹嘘得到这样的支持，此事造成了非常恶劣的影响，除非国王陛 下出面制止。对此，国王陛下立刻回答说： “我们已经给所有我们派驻意 大利的军官发了信，一旦瓦伦蒂诺公爵胆敢采取任何针对佛罗伦萨人或博 洛尼亚人的行动，他们就会立刻调动，毫不犹豫地进攻瓦伦蒂诺公爵，因 此，你们一定会安然无恙的。”然后，国王陛下立刻进入他惯常的抱怨， 而对其他方面，即我提到的王后已经向比萨派出总督，还有卢卡人关于彼 得拉桑塔的事，他只大概回答了一下，说我们破坏了与他签订的条约，未 能首先及时支付这笔钱款，而且直到现在仍然不情不愿，使他很难履约。 我对此能够做出的辩解或声明，由于我和他谈话的时间太长，我担心他的 忍耐有限，就不再回答了。最后，我说执政团的大使还有2天就抵达，他 回答说： “也许他来得太迟了。”然后，我就离开了国王陛下，去找罗贝 泰，和他谈论我上面写到的那些事情，他对我说，拉帕利斯大人去比萨的 事情根本就是无稽之谈；如果皮耶罗 ·德 ·梅迪奇在比萨的话，这绝不是 出于国王陛下的命令，而是应瓦伦蒂诺公爵之邀，他借此观望他在那里是 否有助于公爵的计划取得成功；而国王陛下几次三番地写信给手下，要他</p><p>① 雅 克 · 夏 巴 纳( Jacques Chabannes), 拉帕利斯的领主，法国元帅。 ——贝尔泰利编校本注 ②加斯帕尔 一 世 · 德 · 科利尼( Gaspard I de Coligny),卢万河畔夏蒂永的领主。 ——贝尔泰利编校本注</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>们保卫执政团和博洛尼亚人的利益，此乃千真万确之事。他还补充说(悄 悄地),瓦伦蒂诺公爵的兴旺发达使国王陛下非常不快。关于卢卡人的问 题，他对我说，他们正千方百计地夺回彼得拉桑塔，掏了10000达克特甚 至更多，存在这样的危险，因为国王陛下不满于你们支付这笔钱款拖拖拉 拉，他们可能成功。当我得心应手地回答了所有这些问题后，他对我总结 说：按照他自己的判断，以及其他人对国王陛下和鲁昂教座大人谈论有关 执政团的事情时所说，他确信无疑的是，如果执政团不想留下负面证据， 就永远不要理会那些不符合你们利益的事情。带着这个建议，我离开了罗 贝泰大人。我现在满怀期望等待着大使的到来，看看执政团的事情会有怎 样的转机，并能够更加准确地判断。我要恭敬地提醒诸位大人，这件事自 我们到达这里一开始就非常详细地写明——但在此后没有过多地重复，因 为我不想显得自以为是，而且在城邦中还有许多审慎的公民对法国宫廷的 事务较我们更为驾轻就熟——那就是，执政团要安排某人前来，此人应对 你们忠心友善，并且能够捍卫和保全你们的利益，就像此前所有出使宫廷 的人所做的那样；我只能相信执政团的大使此行已经做好了准备。并且， 我可以向诸位大人保证，如果大使不能至少向罗贝泰大人表达某种程度的 谢意的话，他将发现自己一筹莫展，以致无法寄出一封平常的信件。 德意志使团的成员包括拿骚的菲利普大人以及其他两位级别较低的贵 族 ，他们在昨天获得了国王陛下的接见，并向他作了报告，在座的有鲁昂 教座大人、拉特雷穆瓦耶大人、里尼大人、首席大臣、吉斯元帅、奥兰治 亲王、洛特林侯爵、克拉里大人，教皇大使、西班牙大使和威尼斯大使一 同出席，还有三四个意大利人。大使的提议寻常普通、大而化之，他实际 上要表明，整个帝国都应认识到，全体基督教世界必须武装起来对抗异教 徒的狂热，若非如此，每天都在遭受土耳其人肆意瓜分的基督教共和国就 很难保全；然而，如果作为基督教世界两位领袖的帝国皇帝与笃信王之间 无法达成和平的话，那么,所有的基督教国家就不可能事实上武装起来； 大使就是为了达成此和平的目的而来；大使只在这一点上长篇大论，使用</p><p>Legazioni,commissarie,scritti di governo</p><p>的辞令都是类似的仪式上司空见惯的。在听取这个报告后，国王陛下任命 了4名代表同上述大使一起商讨该和平条约，这4名代表是：教座大人、首 席大臣、波旁大人和吉斯元帅。据说国王陛下去了布洛瓦，里昂方面没有 什么好说的。感谢诸位大人的善意恩惠，再 会 !</p><p>发自图尔，1500年11月24日 仆尼科洛 · 马基雅维利</p><p>信件28</p><p>尊敬的诸位大人： 我收到了十人委员会长官的几封信，回复了我写给诸位大人的几封 信，我向上述长官报告了身边发生的所有与我城利益相关的事，这里就不 再向诸位大人赘述了；促使我写这封信的唯一动机是想让诸位大人认识到 我的诚意，并谦卑地向诸位大人致以问候。我写这封信的进一步动机乃是 基于我对那不勒斯的朱利奥 ·斯库尔齐利亚托大人的情谊，不是由于他为 我个人做过什么特别的事情，而是由于他热情洋溢、富有成效、持续不断 和充满深情的工作有利于我们共和国的自由。因此，我诚挚地向诸位大人 推荐此人，并恭敬地请求诸位大人，如果你们希望继续将他视为你们的朋 友和在此地的捍卫者，如果你们不想因为没有认可朱利奥大人的功劳而被 这里的整个宫廷看作是忘恩负义的，那么,你们一定乐意以你们的掌权 之手帮助他，在他卷入其中的与皮埃尔 · 安东尼奥 · 班迪尼的继承人之 间的诉讼上给予帮助。我向诸位大人保证，当他3天前得到消息说此案由 于禁令尚未做出判决的时候，他对自己遭受的不公义愤填膺，若不是我当 时在场，他肯定会冲上宫廷，为他所受的伤害高声喊冤。他还抱怨了其他 事情：首先，诸位大人将他的案子交给了普通法庭，而这案子本来理当由</p><p>Opere complete di Niccolò Machiavelli</p><p>诸位大人亲自判决；其次，这个普通法庭如此拖延，以致他的对手有时间 得到一份禁令；再次，那个女人已经被解除了禁闭；复次，在佛罗伦萨为 他打官司的那个人完全剥夺了他通过这些程序获得其权益的希望；最后， 在禁令中，他的对手称他是商人和放高利贷者，而他声称自己只想拿回本 钱，愿意放弃所有利息。杰出的诸位大人，我对他的这个案子一无所知， 但我的确知道，诸位大人与国王陛下之间的关系充满变数，至今悬而未 决，能够为你们效劳的人寥寥无几，而人人皆可对你们造成伤害；有鉴于 此，我觉得当务之急是，笼络交好此人，稳住他以随机应变。如果你们不 这么做，那么在收到从佛罗伦萨来的第一封信时，他就会像一道闪电一样 冲上宫廷，从他口中说出的诸位大人的恶言较他先前说的好话更容易被人 相信。他是有一定影响力和信誉的人，能言善辩、大胆无畏、冥顽不化、 令人畏惧，有着无法控制的激情，而且他认定要做的事总是进行到底。我 将此事和盘托出，只是出于我对祖国的热爱，我这么写，是因为我相信这 会对祖国有益。我相信，诸位杰出的大人肯定会谅解我，并以诸位一贯的 善意和睿智裁断此事。我谦卑地向诸位大人致意。</p><p>发自图尔，1500年11月24日 仆尼科洛 · 马基雅维利，国务秘书</p>',37)])])}const h=e(o,[["render",c]]);export{d as __pageData,h as default};
